    <script>
      const mySiema = new Siema({
        duration: 340,
        loop: false,
        onChange: () => updateCurrentSlideState(),
      });

      const slideToggles = document.querySelectorAll(".js-slide-toggle");
      const greenButton = document.querySelector(".next");
      const CTAButton = document.querySelector(".cta");
      const ButtonWrap = document.querySelector(".modal__button-wrap");
      const ButtonWrap2 = document.querySelector(".modal__button-wrap-2");
      CTAButton.style.display = "none";
      ButtonWrap2.style.display = "none";

      function updateCurrentSlideState() {
        slideToggles.forEach((slideToggle, i) => {
          if (mySiema.currentSlide === i) {
            slideToggle.classList.add("is-active");
          } else {
            slideToggle.classList.remove("is-active");
          }
        });
        // this bit of code will get executed when you get to the last slide, hide the main primary action button and show the CTA button
        if (mySiema.currentSlide == slideToggles.length - 1) {
          CTAButton.style.visibility = "visible";
          CTAButton.style.display = "flex";
          ButtonWrap2.style.display = "flex";
          greenButton.style.display = "none";
          ButtonWrap.classList.remove("modal__button-wrap")
          ButtonWrap.classList.add("modal__button-wrap-margin")
        } else {
          greenButton.style.display = "flex";
          CTAButton.style.display = "none";
          ButtonWrap2.style.display = "none";
          ButtonWrap.classList.add("modal__button-wrap")
          ButtonWrap.classList.remove("modal__button-wrap-margin")
        }
      }

      greenButton.addEventListener("click", (event) => {
        //handle click
        mySiema.next();
      });

      greenButton.addEventListener("click", (event) => {
        appboyBridge.logClick("nextCta")
      }, {once : true});
    </script>
